// Minimal React + JSX stubs for type-checking the W85-D Akasha streaming page.
// Cycle 84 lesson: declare hooks as NAMED module exports so that
// `import { useState, useEffect, ... } from 'react'` works in isolated scope.

declare global {
  namespace React {
    type ReactNode =
      | string
      | number
      | boolean
      | null
      | undefined
      | ReactElement
      | ReactNodeArray;
    interface ReactNodeArray extends Array<ReactNode> {}
    type Key = string | number | bigint;
    type Ref<T> = { current: T | null } | ((instance: T | null) => void) | null;

    interface Props {
      children?: ReactNode;
      key?: Key | null;
      ref?: Ref<unknown>;
    }

    interface CSSProperties {
      [key: string]: string | number | undefined;
    }

    interface ReactElement<P = unknown> {
      type: string | ReactComponentType<P> | symbol;
      props: P;
      key: Key | null;
    }

    interface Component<P = unknown, S = unknown> {
      props: P;
      state: S;
      setState(state: Partial<S>): void;
      render(): ReactNode;
    }

    type ReactComponentType<P = unknown> =
      | string
      | ((props: P) => ReactElement | null)
      | (new (props: P) => Component<P>);

    interface SyntheticEvent {
      stopPropagation(): void;
      preventDefault(): void;
      target: { value: string; checked?: boolean };
    }
    interface KeyboardEvent extends SyntheticEvent {
      key: string;
    }
    interface MouseEvent extends SyntheticEvent {
      stopPropagation(): void;
      preventDefault(): void;
      target: { value: string; checked?: boolean };
    }

    type MouseEventHandler<T = unknown> = (event: SyntheticEvent) => void;
    type ChangeEventHandler<T = unknown> = (event: SyntheticEvent) => void;
    type FormEventHandler<T = unknown> = (event: SyntheticEvent) => void;
    type KeyboardEventHandler<T = unknown> = (event: KeyboardEvent) => void;
  }

  namespace JSX {
    interface IntrinsicElements {
      [elem: string]: {
        [attr: string]: unknown;
        key?: React.Key;
        children?: React.ReactNode;
        ref?: React.Ref<unknown>;
        dangerouslySetInnerHTML?: { __html: string };
        onClick?: React.MouseEventHandler;
        onKeyDown?: React.KeyboardEventHandler;
        onChange?: React.ChangeEventHandler;
        onSubmit?: React.FormEventHandler;
        'aria-label'?: string;
      };
    }
    interface Element extends React.ReactElement {}
    interface ElementClass extends React.Component {}
    type ElementType = string | React.ReactComponentType;
  }
}

declare module 'react' {
  // NAMED exports — hooks + types.
  export type ReactNode =
    | string
    | number
    | boolean
    | null
    | undefined
    | ReactElement
    | ReactNodeArray;
  export interface ReactNodeArray extends Array<ReactNode> {}
  export type Key = string | number | bigint;
  export type Ref<T> = { current: T | null } | ((instance: T | null) => void) | null;

  export interface CSSProperties {
    [key: string]: string | number | undefined;
  }

  export interface ReactElement<P = unknown> {
    type: string | ReactComponentType<P> | symbol;
    props: P;
    key: Key | null;
  }

  export interface Component<P = unknown, S = unknown> {
    props: P;
    state: S;
    setState(state: Partial<S>): void;
    render(): ReactNode;
  }

  export type ReactComponentType<P = unknown> =
    | string
    | ((props: P) => ReactElement | null)
    | (new (props: P) => Component<P>);

  export interface SyntheticEvent {
    stopPropagation(): void;
    preventDefault(): void;
    target: { value: string; checked?: boolean };
  }
  export interface KeyboardEvent extends SyntheticEvent {
    key: string;
  }

  export type MouseEventHandler<T = unknown> = (event: SyntheticEvent) => void;
  export type ChangeEventHandler<T = unknown> = (event: SyntheticEvent) => void;
  export type FormEventHandler<T = unknown> = (event: SyntheticEvent) => void;
  export type KeyboardEventHandler<T = unknown> = (event: KeyboardEvent) => void;

  // Hooks.
  export function useState<T>(initial: T | (() => T)): [T, (next: T | ((prev: T) => T)) => void];
  export function useState<T = undefined>(): [T | undefined, (next: T | ((prev: T | undefined) => T)) => void];
  export function useEffect(fn: () => void | (() => void), deps?: ReadonlyArray<unknown>): void;
  export function useRef<T>(initial: T): { current: T };
  export function useRef<T>(initial: T | null): { current: T | null };
  export function useMemo<T>(fn: () => T, deps: ReadonlyArray<unknown>): T;
  export function useCallback<T extends (...args: never[]) => unknown>(fn: T, deps: ReadonlyArray<unknown>): T;
  export function useReducer<S, A>(
    reducer: (state: S, action: A) => S,
    initialState: S,
  ): [S, (action: A) => void];

  // createElement + Fragment (used by the runtime shim if needed).
  export function createElement(type: unknown, props?: unknown, ...children: unknown[]): ReactElement;
  export const Fragment: unique symbol;
}

export {};